32	export const SendEmailForm = ({
33	    opened,
34	    onClose,
35	    players,
36	    onSendEmail,
37	    withinPortal,
38	    withOverlay,
39	}: Props) => {
40	    const [subject, setSubject] = useState('');
41	    const names = players.map((player) => player.name).join(', ');
42	    const emails = Array.from(new Set(players.flatMap((player) => {
43	        const verifiedExtraEmails = player.extraEmails.filter((playerEmail) => playerEmail.verifiedAt);
44	        const preferredExtraEmails = verifiedExtraEmails.length > 0 ? verifiedExtraEmails : player.extraEmails;
45	        return [player.accountEmail, ...preferredExtraEmails.map((playerEmail) => playerEmail.email)];
46	    }).filter((email): email is string => !!email && email.length > 0))).join(',');
47	
48	    const editor = useEditor({
49	        extensions: [
50	            Highlight,
51	            Link,
52	            Placeholder.configure({ placeholder: 'Message text' }),
53	            StarterKit,
54	            TextAlign.configure({ types: ['heading', 'paragraph'] }),
55	            Underline,
56	        ],
57	        content: '',
58	        immediatelyRender: false,
59	    });
60	
61	    if (!editor) return null;
62	
63	    const handleSubmit = async () => {
64	        const id = notifications.show({
65	            loading: true,
66	            title: 'Sending email',
67	            message: 'Sending email...',
68	            autoClose: false,
69	            withCloseButton: false,
70	        });
71	
72	        try {
73	            await onSendEmail({
74	                to: emails,
75	                subject,
76	                html: editor.getHTML(),
77	            });
78	
79	            onClose();
80	            notifications.update({
81	                id,
82	                color: 'teal',
83	                title: 'Email sent',
84	                message: 'Email sent successfully',
85	                icon: <IconCheck size={config.notificationIconSize} />,
86	                loading: false,
87	                autoClose: config.notificationAutoClose,
88	            });
89	        } catch (err) {
90	            captureUnexpectedError(err, {
91	                layer: 'client',
92	                component: 'SendEmailForm',
93	                action: 'sendEmail',
94	                route: '/footy/admin/players',
95	                extra: {
96	                    recipientCount: players.length,
97	                },
98	            });
99	            notifications.update({
100	                id,
101	                color: 'red',
102	                title: 'Error',
103	                message: toPublicMessage(err, 'Failed to send email.'),
104	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
105	                loading: false,
106	                autoClose: config.notificationAutoClose,
107	            });
108	        }
109	    };
110	
111	    return (
112	        <Modal
113	            opened={opened}
114	            onClose={onClose}
115	            title="Send Mail to Players"
116	            size="lg"
117	            withinPortal={withinPortal}
118	            withOverlay={withOverlay}
119	        >
120	            <Tooltip label={names} multiline>
121	                <Text size="sm" mt="sm" lineClamp={1}>
122	                    <IconUser size={16} className={classes.users} />
123	                    <strong>To:</strong> {names}
124	                </Text>
125	            </Tooltip>
126	            <form onSubmit={(e) => { e.preventDefault(); void handleSubmit(); }}>
127	                <TextInput
128	                    label="Subject"
129	                    value={subject}
130	                    onChange={(event) => setSubject(event.currentTarget.value)}
131	                    required
132	                    mt="md"
133	                />
134	
135	                <RichTextEditor editor={editor} mt="md">
136	                    <RichTextEditor.Toolbar sticky stickyOffset={60}>
137	                        <RichTextEditor.ControlsGroup>
138	                            <RichTextEditor.Bold />
139	                            <RichTextEditor.Italic />
