29	/**
30	 * Unpacks and validates page parameters and search parameters for a player
31	 * page.
32	 *
33	 * This function performs the following operations:
34	 * - Extracts and validates the player ID (either numeric or login string)
35	 * - Retrieves the player from the database
36	 * - Validates the requested year against the player's active years
37	 * - Constructs canonical URLs and redirects if the current URL doesn't match
38	 * - Returns the player data, selected year, and all active years
39	 *
40	 * @param params - The page route parameters containing the player ID
41	 * @param searchParams - The URL search parameters, optionally containing a year
42	 * filter
43	 * @returns A promise resolving to an object containing the player record,
44	 * selected year, and array of active years
45	 * @throws {notFound} When the player is not found or the requested year is
46	 * invalid
47	 * @throws {permanentRedirect} When the current URL doesn't match the canonical
48	 * URL format
49	 */
50	const unpackParams = cache(async (
51	    params: PageProps['params'],
52	    searchParams: PageProps['searchParams'],
53	) => {
54	    const { id } = await params;
55	
56	    const resolvedSearchParams = await searchParams;
57	    const playerId = z.coerce.number().int().min(1).safeParse(id);
58	    const player = await (playerId.success ?
59	        playerService.getById(playerId.data) :
60	        playerService.getByLogin(id));
61	    if (!player) notFound();
62	
63	    const activeYears = await playerService.getYearsActive(player.id);
64	    const yearResult = z.coerce.number().int().min(0).safeParse(resolvedSearchParams?.year ?? 0);
65	    const year = yearResult.success ? yearResult.data : undefined;
66	    if (year === undefined || !activeYears.includes(year)) notFound();
67	
68	    const canonicalSearch = year ? `?year=${year}` : '';
69	    const canonicalUrl = `/footy/player/${player.id}${canonicalSearch}`;
70	    const currentSearch = resolvedSearchParams?.year ? `?year=${resolvedSearchParams.year}` : '';
71	    const currentUrl = `/footy/player/${id}${currentSearch}`;
72	    if (currentUrl !== canonicalUrl) permanentRedirect(canonicalUrl);
73	
74	    return { player, year, activeYears };
75	});
