94	
95	    const role = await getUserRole();
96	    const isAuthenticated = role !== 'none';
97	    const isAdmin = role === 'admin';
98	    const [
99	        introducedBy,
100	        lastPlayed,
101	        lastWon,
102	        history,
103	        clubs,
104	        countries,
105	        arse,
106	        record,
