108	        nextPlayer,
109	    ] = await Promise.all([
110	        player.introducedBy != null ? playerService.getById(player.introducedBy) : Promise.resolve(null),
111	        playerService.getLastResult(player.id, year),
112	        playerService.getLastResult(player.id, year, 3),
113	        outcomeService.getHistoryByPlayer(player.id, year, player.joined ?? undefined, player.finished ?? undefined),
114	        clubSupporterService.getByPlayer(player.id),
115	        countrySupporterService.getByPlayer(player.id),
116	        isAdmin ? arseService.getByPlayer(player.id) : Promise.resolve(null),
117	        playerRecordService.getForYearByPlayer(year, player.id),
118	        playerService.getPrevious(player.id),
119	        playerService.getNext(player.id),
120	    ]);
121	
122	    const trophies = new Map<TableName, PlayerRecordType[]>();
123	    await Promise.all(TableNameSchema.options.map(async (table) => {
124	        const winners = await playerRecordService.getWinners(table, year, player.id);
125	        trophies.set(table, winners);
126	    }));
127	
128	    return (
129	        <>
130	            <AutoRefresh channels={[FootyChannel.Players, FootyChannel.Results]} />
131	            <PlayerProfile
132	                key={player.id}
133	                player={player}
134	                introducedBy={introducedBy}
135	                year={year}
136	                history={history}
137	                lastPlayed={lastPlayed}
138	                lastWon={lastWon}
139	                clubs={clubs}
140	                countries={countries}
141	                arse={arse}
142	                activeYears={activeYears}
143	                record={record}
144	                prevPlayer={prevPlayer}
145	                nextPlayer={nextPlayer}
146	                trophies={trophies}
147	                isAuthenticated={isAuthenticated}
148	                isAdmin={isAdmin}
149	            />
150	        </>
