/**
 * Get a single player by id, including email data (account email and extra emails).
 * @param id The numeric ID for the player
 * @returns A promise that resolves to the player with email data, or null if not found
 */
async getDataById(id: number): Promise<PlayerDataDisplayType | null> {
    const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
    const player = await prisma.player.findUnique({
        where,
        include: {
            extraEmails: {
                orderBy: [
                    { verifiedAt: 'desc' },
                    { createdAt: 'desc' },
                ],
            },
        },
    });
    if (!player) return null;

    const { extraEmails, ...rest } = player;
    const accountEmail = (rest as { accountEmail?: string | null }).accountEmail ?? null;
    const playerData = {
        ...rest,
        accountEmail,
        extraEmails,
        firstResponded: null,
        lastResponded: null,
        firstPlayed: null,
        lastPlayed: null,
        gamesPlayed: 0,
        gamesWon: 0,
        gamesDrawn: 0,
        gamesLost: 0,
    } satisfies PlayerDataType;

    return this.sanitizePlayerName(playerData);
}

